import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from "axios";
import './ProfessorPage.css';

interface Assignment {
    assid: number;
    asstitle: string;
    createdat: string;
    student: {
        username: string;
    };
}

const ProfessorPage: React.FC = () => {
    const username = localStorage.getItem('username') || 'Profesor';
    const navigate = useNavigate();

    const [assignments, setAssignments] = useState<Assignment[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const fetchAssignments = async () => {
        const token = localStorage.getItem('token');
        try {
            setLoading(true);
            const response = await axios.get<Assignment[]>(
                'http://localhost:9090/api/assignments/professor/me',
                {
                    headers: { Authorization: `Bearer ${token}` },
                }
            );
            setAssignments(response.data);
            setError(null);
        } catch (err) {
            console.error("Eroare la preluarea temelor:", err);
            setError("Nu am putut încărca temele.");
        } finally {
            setLoading(false);
        }
    };

    const handleCreateClick = () => {
        navigate('/create');
    };

    useEffect(() => {
        fetchAssignments();
    }, []);

    const handleDelete = async (id: number) => {
        if (window.confirm('Ești sigur că vrei să ștergi această temă?')) {
            const token = localStorage.getItem('token');
            try {
                await axios.delete(`http://localhost:9090/api/assignments/${id}`, {
                    headers: { Authorization: `Bearer ${token}` },
                });
                fetchAssignments();
            } catch (err) {
                console.error("Eroare la ștergerea temei:", err);
                alert("Eroare la ștergerea temei.");
            }
        }
    };

    const handleGrade = (id: number) => {
        // ✅ corectat — trebuie folosite backticks (``) pentru template string
        navigate(`/grade/${id}`);
    };

    const renderAssignmentsTable = () => {
        if (loading) return <p className="loading-message">Se încarcă temele...</p>;
        if (error) return <p className="error-message">{error}</p>;
        if (assignments.length === 0) {
            return <p className="loading-message">Nu ai creat nicio temă încă.</p>;
        }

        return (
            <table className="assignment-table-prof">
                <thead>
                <tr>
                    <th>Titlu</th>
                    <th>Student</th>
                    <th>Data Creării</th>
                    <th>Acțiuni</th>
                </tr>
                </thead>
                <tbody>
                {assignments.map((assignment) => (
                    <tr key={assignment.assid}>
                        <td>{assignment.asstitle}</td>
                        <td>{assignment.student.username}</td>
                        <td>{new Date(assignment.createdat).toLocaleDateString('ro-RO')}</td>
                        <td className="actions-cell">
                            <button
                                className="action-button grade-button"
                                onClick={() => handleGrade(assignment.assid)}
                            >
                                Corectează
                            </button>
                            <button
                                className="action-button delete-button"
                                onClick={() => handleDelete(assignment.assid)}
                            >
                                Șterge
                            </button>
                        </td>
                    </tr>
                ))}
                </tbody>
            </table>
        );
    };

    return (
        <div className="professor-page-container">
            <div className="Patrat_stanga">
                <div className="dashboard-card card-welcome">
                    <h2>Bine ai venit, {username}!</h2>
                    <p>Selectează o temă sau un test pentru elevi:</p>
                    <button onClick={handleCreateClick} className="card-button">
                        Creează o Temă Nouă
                    </button>

                    {/* 🔽 Am mutat aici tabelul cu temele */}
                    <div style={{ marginTop: "30px" }}>
                        <h3>Teme Create de Tine</h3>
                        {renderAssignmentsTable()}
                    </div>
                </div>
            </div>

            {/* Patratele din mijloc și dreapta rămân goale pentru viitor */}
            <div className="Patrat_mijloc"></div>
            <div className="Patrat_dreapta"></div>
        </div>
    );
};

export default ProfessorPage;
